    [Fact]
    public async Task Upload_ReturnsOk200_EchoingServiceReturnedPath_WhenPathIsEmpty()
    {
        // After the refactor the response path is sourced from the service
        // return value (the source of truth), not reconstructed by the
        // controller. The controller must echo it verbatim.
        var fake = new FakeFileService { UploadedPath = "upload.txt" };
        var controller = CreateController(fake);
        var file = FormFileFactory.CreateFormFile("upload.txt", "payload");

        var result = await controller.Upload(string.Empty, file);

        var ok = Assert.IsType<OkObjectResult>(result);
        Assert.Equal(StatusCodes.Status200OK, ok.StatusCode);
        Assert.Equal("upload.txt", GetProperty(ok.Value!, "path"));
    }

    [Fact]
